<?php
namespace Nistruct\ContentAI\Controller\Adminhtml\BulkReport;
use Magento\Backend\App\Action; use Magento\Framework\Registry; use Magento\Framework\View\Result\PageFactory; use Nistruct\ContentAI\Model\BulkReportFactory;
class View extends Action { public const ADMIN_RESOURCE='Nistruct_ContentAI::bulk_report'; private $resultPageFactory; private $registry; private $reportFactory; public function __construct(Action\Context $context, PageFactory $resultPageFactory, Registry $registry, BulkReportFactory $reportFactory){parent::__construct($context);$this->resultPageFactory=$resultPageFactory;$this->registry=$registry;$this->reportFactory=$reportFactory;} public function execute(){ $id=(int)$this->getRequest()->getParam('id');$r=$this->reportFactory->create()->load($id); if(!$r->getId()){ $this->messageManager->addErrorMessage(__('Bulk report no longer exists.')); return $this->_redirect('*/*/index'); } $this->registry->register('current_contentai_bulk_report',$r); $p=$this->resultPageFactory->create();$p->setActiveMenu('Nistruct_ContentAI::bulk_report_menu');$p->getConfig()->getTitle()->prepend(__('ContentAI Bulk Report #%1',$r->getId()));return $p;} protected function _isAllowed(){return $this->_authorization->isAllowed(self::ADMIN_RESOURCE);} }
